import os
from pathlib import Path
from typing import TYPE_CHECKING

from virtualenv.util.path import copy

from .base import PipInstall

if TYPE_CHECKING:
    from collections.abc import Generator


class CopyPipInstall(PipInstall):
    def _sync(self, src: Path, dst: Path) -> None:
        copy(src, dst)

    def _generate_new_files(self) -> set[Path]:
        # create the pyc files
        new_files = super()._generate_new_files()
        new_files.update(self._cache_files())
        return new_files

    def _cache_files(self) -> Generator[Path, None, None]:
        version = self._creator.interpreter.version_info
        py_c_ext = f".{self._creator.interpreter.implementation.lower()}-{version.major}{version.minor}.pyc"
        for root, dirs, files in os.walk(str(self._image_dir), topdown=True):
            root_path = Path(root)
            for name in files:
                if name.endswith(".py"):
                    yield root_path / f"{name[:-3]}{py_c_ext}"
            for name in dirs:
                yield root_path / name / "__pycache__"

    def _fix_records(self, extra_record_data: set[Path]) -> None:
        extra_record_data_str = self._records_text(extra_record_data)
        with (self._dist_info / "RECORD").open("ab") as file_handler:  # ty: ignore[unsupported-operator]
            file_handler.write(extra_record_data_str.encode("utf-8"))


__all__ = [
    "CopyPipInstall",
]

from __future__ import annotations

from typing import TYPE_CHECKING
from typing import cast

from cleo.io.inputs.string_input import StringInput
from cleo.io.io import IO
from cleo.io.outputs.buffered_output import BufferedOutput


if TYPE_CHECKING:
    from cleo.io.inputs.input import Input


class BufferedIO(IO):
    def __init__(
        self,
        input: Input | None = None,
        decorated: bool = False,
        supports_utf8: bool = True,
    ) -> None:
        super().__init__(
            input or StringInput(""),
            BufferedOutput(decorated=decorated, supports_utf8=supports_utf8),
            BufferedOutput(decorated=decorated, supports_utf8=supports_utf8),
        )

    def fetch_output(self) -> str:
        return cast("BufferedOutput", self._output).fetch()

    def fetch_error(self) -> str:
        return cast("BufferedOutput", self._error_output).fetch()

    def clear(self) -> None:
        cast("BufferedOutput", self._output).clear()
        cast("BufferedOutput", self._error_output).clear()

    def clear_output(self) -> None:
        cast("BufferedOutput", self._output).clear()

    def clear_error(self) -> None:
        cast("BufferedOutput", self._error_output).clear()

    def supports_utf8(self) -> bool:
        return cast("BufferedOutput", self._output).supports_utf8()

    def clear_user_input(self) -> None:
        self._input.stream.truncate(0)
        self._input.stream.seek(0)

    def set_user_input(self, user_input: str) -> None:
        self.clear_user_input()

        self._input.stream.write(user_input)
        self._input.stream.seek(0)

from __future__ import annotations

from typing import TYPE_CHECKING

from poetry.core.packages.path_dependency import PathDependency


if TYPE_CHECKING:
    from collections.abc import Iterable
    from pathlib import Path


class FileDependency(PathDependency):
    def __init__(
        self,
        name: str,
        path: Path,
        *,
        directory: str | None = None,
        groups: Iterable[str] | None = None,
        optional: bool = False,
        base: Path | None = None,
        extras: Iterable[str] | None = None,
    ) -> None:
        super().__init__(
            name,
            path,
            source_type="file",
            groups=groups,
            optional=optional,
            base=base,
            subdirectory=directory,
            extras=extras,
        )
        # Attributes must be immutable for clone() to be safe!
        # (For performance reasons, clone only creates a copy instead of a deep copy).

    @property
    def directory(self) -> str | None:
        return self.source_subdirectory

    @property
    def base_pep_508_name(self) -> str:
        requirement = super().base_pep_508_name

        if self.directory:
            requirement += f"#subdirectory={self.directory}"

        return requirement

    def _validate(self) -> str:
        message = super()._validate()
        if message:
            return message

        if self._full_path.is_dir():
            return (
                f"{self._full_path} for {self.pretty_name} is a directory,"
                " expected a file"
            )
        return ""

from __future__ import annotations

from typing import TYPE_CHECKING

from poetry.installation.operations.operation import Operation


if TYPE_CHECKING:
    from poetry.core.packages.package import Package


class Update(Operation):
    def __init__(
        self,
        initial: Package,
        target: Package,
        reason: str | None = None,
        priority: int = 0,
    ) -> None:
        self._initial_package = initial
        self._target_package = target

        super().__init__(reason, priority=priority)

    @property
    def initial_package(self) -> Package:
        return self._initial_package

    @property
    def target_package(self) -> Package:
        return self._target_package

    @property
    def package(self) -> Package:
        return self._target_package

    @property
    def job_type(self) -> str:
        return "update"

    def __str__(self) -> str:
        init_version = self.format_version(self.initial_package)
        target_version = self.format_version(self.target_package)
        return (
            f"Updating {self.initial_package.pretty_name} ({init_version}) "
            f"to {self.target_package.pretty_name} ({target_version})"
        )

    def __repr__(self) -> str:
        init_version = self.format_version(self.initial_package)
        target_version = self.format_version(self.target_package)
        return (
            f"<Update {self.initial_package.pretty_name} ({init_version}) "
            f"to {self.target_package.pretty_name} ({target_version})>"
        )

